            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= currentVal) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    const pq: [number, number, number, number][] = [[0, 0, 0, 0]];

    const directions = [[0, 1], [1, 0]];

    while (pq.length > 0) {
        const [cost, i, j, t] = pq.shift() as [number, number, number, number];
        if (cost > dist[i][j][t]) continue;
        if (i === m - 1 && j === n - 1) return cost;

        for (const [dx, dy] of directions) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    pq.push([newCost, ni, nj, t]);
                }
            }
        }

        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                if (cost < dist[x][y][t + 1]) {
                    dist[x][y][t + 1] = cost;
                    pq.push([cost, x, y, t + 1]);
                }
            }
        }
    }

    return dist[m - 1][n - 1][k];
}
